// Para que sirve: Pagina de detalle de producto con compartir y acciones de compra.
// Entradas: Props, hooks de contexto y/o estado local segun el archivo.
// Flujo principal: Lee estado, aplica reglas de UI/negocio y renderiza la vista.
// Donde tocar cambios: Ajusta este archivo para modificar su comportamiento principal.
import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { Link, Navigate, useNavigate, useParams } from 'react-router-dom';
import useCart from '../context/useCart';
import useAuth from '../context/useAuth';
import useProducts from '../context/useProducts';
import useLanguage from '../context/useLanguage';
import useDocumentTitle from '../hooks/useDocumentTitle';

/**
 * Copies text to clipboard with a fallback for browsers without clipboard API.
 * @param {string} text
 * @returns {Promise<void>}
 */
async function copyToClipboard(text) {
  if (navigator.clipboard?.writeText) {
    await navigator.clipboard.writeText(text);
    return;
  }
  const el = document.createElement('textarea');
  el.value = text;
  el.style.position = 'fixed';
  el.style.opacity = '0';
  document.body.appendChild(el);
  el.select();
  document.execCommand('copy');
  document.body.removeChild(el);
}

/**
 * Parses and validates the product id from route params.
 * @param {string | undefined} value
 * @returns {number | null}
 */
function parseProductId(value) {
  const parsed = Number.parseInt(value || '', 10);
  return Number.isNaN(parsed) || parsed <= 0 ? null : parsed;
}

/**
 * Ensures quantity remains within supported boundaries.
 * @param {number} value
 * @returns {number}
 */
function clampQuantity(value) {
  return Math.min(99, Math.max(1, value));
}

/**
 * Product detail page with direct actions for cart and checkout.
 */
export default function ProductDetail() {
  const navigate = useNavigate();
  const { id } = useParams();
  const { dispatch, cart, isFavorite, toggleFavorite, showToast } = useCart();
  const { user } = useAuth();
  const { products } = useProducts();
  const { t, formatCurrency, translateCategory, translateProductText } = useLanguage();
  const isAdmin = user?.role === 'admin';
  const [quantity, setQuantity] = useState(1);
  const [quantityNotice, setQuantityNotice] = useState('');
  const [shareState, setShareState] = useState('idle');
  const shareResetTimeoutRef = useRef(null);

  const productId = parseProductId(id);
  // Resolve product early so the dynamic title can be set before any early returns.
  const product = products.find((item) => item.id === productId);
  // WCAG 2.4.2: title updates reactively as soon as the product is resolved.
  useDocumentTitle(product ? translateProductText(product.name) : t('productDetail.title'));

  const translatedProductName = useMemo(
    () => (product ? translateProductText(product.name) : ''),
    [product, translateProductText]
  );
  const translatedProductDescription = useMemo(
    () => (product ? translateProductText(product.description) : ''),
    [product, translateProductText]
  );
  const translatedProductCategory = useMemo(
    () => (product ? translateCategory(product.category) : ''),
    [product, translateCategory]
  );

  const relatedProducts = useMemo(() => products
    .filter((p) => product && p.category === product.category && p.id !== product.id)
    .slice(0, 3), [product, products]);

  const relatedProductCards = useMemo(() => relatedProducts.map((item) => ({
    ...item,
    translatedName: translateProductText(item.name),
    translatedCategory: translateCategory(item.category),
    formattedPrice: formatCurrency(item.price),
  })), [formatCurrency, relatedProducts, translateCategory, translateProductText]);

  const cartItem = useMemo(
    () => (product ? cart.find((item) => item.id === product.id) : null),
    [cart, product]
  );
  const favorite = useMemo(() => (product ? isFavorite(product.id) : false), [isFavorite, product]);
  const itemForCart = useMemo(() => (product ? { ...product, quantity } : null), [product, quantity]);

  useEffect(() => () => {
    if (shareResetTimeoutRef.current != null) {
      window.clearTimeout(shareResetTimeoutRef.current);
    }
  }, []);

  /** Shares the product page or copies URL to clipboard as fallback. */
  const handleShare = useCallback(async () => {
    if (!product) {
      return;
    }

    const url = window.location.href;
    const shareData = { title: product.name, text: product.description, url };
    try {
      if (navigator.share && navigator.canShare?.(shareData)) {
        await navigator.share(shareData);
      } else {
        await copyToClipboard(url);
        setShareState('copied');
        if (shareResetTimeoutRef.current != null) {
          window.clearTimeout(shareResetTimeoutRef.current);
        }
        shareResetTimeoutRef.current = window.setTimeout(() => {
          setShareState('idle');
          shareResetTimeoutRef.current = null;
        }, 1800);
      }
    } catch {
      // User cancelled share or API unavailable: no extra feedback needed.
    }
  }, [product]);

  /**
   * Updates quantity from number input with safe boundaries.
   * @param {React.ChangeEvent<HTMLInputElement>} event
   */
  const handleQuantityChange = useCallback((event) => {
    const rawInput = event.target.value;
    const rawValue = Number.parseInt(rawInput, 10);
    if (Number.isNaN(rawValue)) {
      setQuantity(1);
      setQuantityNotice(t('productDetail.quantityAdjusted', { quantity: 1 }));
      return;
    }

    const clampedValue = clampQuantity(rawValue);
    setQuantity(clampedValue);

    if (clampedValue !== rawValue) {
      setQuantityNotice(t('productDetail.quantityAdjusted', { quantity: clampedValue }));
      return;
    }

    if (!rawInput.trim()) {
      setQuantityNotice(t('productDetail.quantityAdjusted', { quantity: 1 }));
      return;
    }

    setQuantityNotice('');
  }, [t]);

  /** Adds the current product to cart and notifies user. */
  const handleAdd = useCallback(() => {
    if (!itemForCart) {
      return;
    }

    dispatch({ type: 'ADD_ORDER_ITEMS', payload: { items: [itemForCart] } });
    setQuantityNotice('');
    showToast(t('productDetail.addedQuantity', { quantity, name: translatedProductName }), 'success');
  }, [dispatch, itemForCart, quantity, showToast, t, translatedProductName]);

  /** Adds product to cart and navigates to checkout for quick purchase. */
  const handleBuy = useCallback(() => {
    if (!itemForCart) {
      return;
    }

    dispatch({ type: 'ADD_ORDER_ITEMS', payload: { items: [itemForCart] } });
    setQuantityNotice('');
    showToast(t('productDetail.readyToBuyQuantity', { quantity, name: translatedProductName }), 'success');
    navigate('/checkout');
  }, [dispatch, itemForCart, navigate, quantity, showToast, t, translatedProductName]);

  const handleToggleFavorite = useCallback(() => {
    if (!product) {
      return;
    }

    toggleFavorite(product);
  }, [product, toggleFavorite]);

  const decreaseQuantity = useCallback(() => {
    setQuantity((prev) => clampQuantity(prev - 1));
  }, []);

  const increaseQuantity = useCallback(() => {
    setQuantity((prev) => clampQuantity(prev + 1));
  }, []);

  if (!productId || !product) {
    return <Navigate to="/not-found" replace />;
  }

  return (
    <main className="max-w-5xl mx-auto px-4 py-8">
      <nav className="mb-4 flex flex-wrap items-center gap-2 text-sm text-gray-500" aria-label={t('common.breadcrumb')}>
        <Link to="/" className="hover:text-indigo-600 transition focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-indigo-600 rounded-sm">
          {t('notFound.home')}
        </Link>
        <span aria-hidden="true">/</span>
        <span>{translatedProductCategory}</span>
        <span aria-hidden="true">/</span>
        <span className="text-gray-700 font-medium" aria-current="page">{translatedProductName}</span>
      </nav>

      <Link
        to="/"
        className="inline-flex items-center rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm font-medium text-gray-700 transition hover:bg-gray-50 focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-indigo-600"
      >
        {t('productDetail.backToProducts')}
      </Link>

      <section className="mt-6 grid grid-cols-1 lg:grid-cols-2 gap-8 bg-white rounded-2xl shadow p-6" aria-label={t('productDetail.sectionLabel')}>
        <img
          src={product.image}
          alt={translatedProductName}
          className="w-full h-80 lg:h-105 rounded-xl object-cover"
          loading="eager"
          decoding="async"
        />

        <div className="flex flex-col gap-4">
          <p className="text-xs font-semibold tracking-wide uppercase text-indigo-600">{translatedProductCategory}</p>
          <div className="flex items-start justify-between gap-3">
            <h1 className="text-3xl font-bold text-gray-900">{translatedProductName}</h1>
            <button
              type="button"
              onClick={handleShare}
              className="shrink-0 rounded-lg border border-gray-300 bg-white px-3 py-1.5 text-sm font-medium text-gray-700 transition hover:bg-gray-50 focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-indigo-600"
              aria-label={t('productDetail.share')}
            >
              {shareState === 'copied' ? t('common.copiedLink') : t('productDetail.share')}
            </button>
          </div>
          <p className="text-gray-600 leading-relaxed">{translatedProductDescription}</p>
          <p className="text-3xl font-extrabold text-gray-900">{formatCurrency(product.price)}</p>

          {!isAdmin && (
            <button
              type="button"
              onClick={handleToggleFavorite}
              className={`w-fit rounded-full px-3 py-1.5 text-sm font-semibold transition focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-indigo-600 ${
                favorite
                  ? 'bg-rose-100 text-rose-700 hover:bg-rose-200'
                  : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
              }`}
              aria-pressed={favorite}
              aria-label={favorite
                ? t('productCard.removeFavorite', { name: translatedProductName })
                : t('productCard.addFavorite', { name: translatedProductName })}
            >
              {favorite ? t('productCard.favoriteOn') : t('productCard.favoriteOff')}
            </button>
          )}

          {!isAdmin && (
            <div className="mt-2 flex flex-wrap items-end gap-3">
              <label className="w-28" htmlFor="product-quantity">
                <span className="mb-1 block text-xs font-semibold uppercase tracking-wide text-gray-500">{t('productDetail.quantity')}</span>
                <input
                  id="product-quantity"
                  type="number"
                  min={1}
                  max={99}
                  step={1}
                  value={quantity}
                  onChange={handleQuantityChange}
                  className="w-full rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
                  aria-describedby={quantityNotice ? 'product-quantity-notice' : undefined}
                />
              </label>
              <button
                type="button"
                onClick={decreaseQuantity}
                className="rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm font-semibold text-gray-700 transition hover:bg-gray-50 focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-indigo-600"
                aria-label={t('productDetail.decreaseQuantity')}
                disabled={quantity <= 1}
              >
                -
              </button>
              <button
                type="button"
                onClick={increaseQuantity}
                className="rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm font-semibold text-gray-700 transition hover:bg-gray-50 focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-indigo-600"
                aria-label={t('productDetail.increaseQuantity')}
                disabled={quantity >= 99}
              >
                +
              </button>
            </div>
          )}

          {!isAdmin && quantityNotice && (
            <p id="product-quantity-notice" className="text-xs text-amber-700" role="status" aria-live="polite" aria-atomic="true">
              {quantityNotice}
            </p>
          )}

          {!isAdmin && (
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              <button
                type="button"
                onClick={handleAdd}
                className="rounded-lg bg-indigo-600 px-4 py-2.5 text-sm font-semibold text-white transition hover:bg-indigo-700 focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-indigo-600"
              >
                {t('productCard.addProduct')}
              </button>
              <button
                type="button"
                onClick={handleBuy}
                className="rounded-lg bg-emerald-600 px-4 py-2.5 text-sm font-semibold text-white transition hover:bg-emerald-700 focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-emerald-600"
              >
                {t('productCard.buy')}
              </button>
            </div>
          )}

          {isAdmin && (
            <p className="rounded-xl border border-indigo-200 bg-indigo-50 px-3 py-2 text-sm text-indigo-800">
              {t('productDetail.adminHint')}
            </p>
          )}

          {!isAdmin && (
            <p className="text-xs text-gray-500">
              {cartItem
                ? t('productDetail.alreadyInCart', { count: cartItem.quantity, suffix: cartItem.quantity !== 1 ? 'es' : '' })
                : t('productDetail.notInCartYet')}
            </p>
          )}
        </div>
      </section>

      {relatedProducts.length > 0 && (
        <section className="mt-12 bg-gray-50 rounded-2xl p-8" aria-label={t('productDetail.relatedTitle')}>
          <h2 className="text-2xl font-bold text-gray-900 mb-6">{t('productDetail.relatedTitle')}</h2>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            {relatedProductCards.map((p) => (
              <Link
                key={p.id}
                to={`/producto/${p.id}`}
                className="group bg-white rounded-lg shadow hover:shadow-md transition overflow-hidden"
                aria-label={t('productCard.viewLabel', { name: p.translatedName })}
              >
                <img
                  src={p.image}
                  alt={p.translatedName}
                  className="w-full h-40 object-cover group-hover:opacity-90 transition"
                  loading="lazy"
                  decoding="async"
                />
                <div className="p-3">
                  <p className="text-xs text-indigo-600 font-semibold uppercase">{p.translatedCategory}</p>
                  <p className="text-sm font-medium text-gray-800 truncate group-hover:text-indigo-600 transition">{p.translatedName}</p>
                  <p className="text-sm font-bold text-gray-900 mt-1">{p.formattedPrice}</p>
                </div>
              </Link>
            ))}
          </div>
        </section>
      )}
    </main>
  );
}
